hibernate-mapping.sql-query:
		
		CREATE procedure [dbo].[ROI_Conversion_Get_Facilities_RequestMain]
			@requestId bigint
		as
		BEGIN
			BEGIN TRY
				declare @request xml;
				select @request = RequestMainXML from [ROI_RequestMain] where [ROI_RequestMain_Seq] = @requestId;
				select
					NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY]
				from @request.nodes('/request/item[@source="hpf"]/patient') as t(c)
				UNION
				select
					[FACILITY] = case t.c.value('is-freeformfacility[1]','varchar(10)') when 'False' then t.c.value('facility[1]','varchar(10)') when 'true' then NULL else t.c.value('facility[1]','varchar(10)') end
				from @request.nodes('/request/item[@source="roi"]/patient') as t(c);
			END TRY
			BEGIN CATCH
				DECLARE @ErrMsg nvarchar(4000), @ErrSeverity int, @ErrLine int;
				SELECT
				@ErrSeverity = ERROR_SEVERITY(),
				@ErrLine = ERROR_LINE(),
				@ErrMsg = ERROR_MESSAGE();
				RAISERROR('Error Message: %s; Error Line: %d', @ErrSeverity, 1, @ErrMsg, @ErrLine)
			END CATCH
		END

		
		CREATE procedure [dbo].[ROI_Conversion_Get_All_Facilities_RequestMain]
		as
		BEGIN
			BEGIN TRY
				declare @request xml;
				declare @requestId bigint;
				declare @tmp table ([FACILITY] varchar(255));
				set @requestId = (select top 1 [ROI_RequestMain_seq] from [ROI_RequestMain] order by [ROI_RequestMain_seq])
				while @requestId is not null 
				begin
					select @request = RequestMainXML from [ROI_RequestMain] where [ROI_RequestMain_Seq] = @requestId;
					insert into @tmp
					select
						NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY]
					from @request.nodes('/request/item[@source="hpf"]/patient') as t(c)
					UNION
					select
						[FACILITY] = case t.c.value('is-freeformfacility[1]','varchar(10)') when 'False' then t.c.value('facility[1]','varchar(10)') when 'true' then NULL else t.c.value('facility[1]','varchar(10)') end
					from @request.nodes('/request/item[@source="roi"]/patient') as t(c);
					set @requestId = (select top 1 [ROI_RequestMain_seq] from [ROI_RequestMain] where [ROI_RequestMain_seq] > @requestId order by [ROI_RequestMain_seq])
				end
				select distinct [FACILITY] from @tmp
			END TRY
			BEGIN CATCH
				DECLARE @ErrMsg nvarchar(4000), @ErrSeverity int, @ErrLine int;
				SELECT
				@ErrSeverity = ERROR_SEVERITY(),
				@ErrLine = ERROR_LINE(),
				@ErrMsg = ERROR_MESSAGE();
				RAISERROR('Error Message: %s; Error Line: %d', @ErrSeverity, 1, @ErrMsg, @ErrLine)
			END CATCH
		END
